// netlify/functions/create-executive.js
// Phase 3 Implementation — Executive Account Creation (Server-Side)
//
// This Netlify Edge Function creates Supabase Auth users using the SERVICE ROLE KEY.
// The key is stored as SUPABASE_SERVICE_ROLE_KEY in Netlify environment variables.
// It must NEVER appear in client-side JavaScript.
//
// Caller: dashboard.js (Executives tab, chapter_admin / president only)
// Expected request body: {
//   email: string,
//   tempPassword: string,     ← auto-generated by the client before calling
//   fullName: string,
//   role: string,             ← one of the allowed exec roles (not 'super_admin')
//   universityId: string      ← from sessionStorage.nags_university
// }
//
// On success: returns { authUserId, execId, email, tempPassword }
// On failure: returns { error: string }

const ALLOWED_ROLES = [
  'chapter_admin', 'president', 'vice_president',
  'pro', 'financial_sec', 'secretary', 'welfare', 'organizing_sec'
];

export default async (request) => {
  if (request.method === 'OPTIONS') {
    return new Response(null, {
      status: 204,
      headers: {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type'
      }
    });
  }

  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Method not allowed.' }), {
      status: 405, headers: { 'Content-Type': 'application/json' }
    });
  }

  const serviceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
  const supabaseUrl = process.env.SUPABASE_URL;

  if (!serviceKey || !supabaseUrl) {
    return new Response(JSON.stringify({
      error: 'Server not configured. Add SUPABASE_SERVICE_ROLE_KEY and SUPABASE_URL to Netlify env vars.'
    }), { status: 503, headers: { 'Content-Type': 'application/json' } });
  }

  let body;
  try { body = await request.json(); }
  catch {
    return new Response(JSON.stringify({ error: 'Invalid JSON body.' }), {
      status: 400, headers: { 'Content-Type': 'application/json' }
    });
  }

  const { email, tempPassword, fullName, role, universityId } = body;

  // Validation
  if (!email || !tempPassword || !fullName || !role || !universityId) {
    return new Response(JSON.stringify({ error: 'Missing required fields: email, tempPassword, fullName, role, universityId.' }), {
      status: 400, headers: { 'Content-Type': 'application/json' }
    });
  }

  if (!ALLOWED_ROLES.includes(role)) {
    return new Response(JSON.stringify({ error: `Invalid role. Allowed: ${ALLOWED_ROLES.join(', ')}` }), {
      status: 400, headers: { 'Content-Type': 'application/json' }
    });
  }

  try {
    // Step 1 — Create Supabase Auth user
    const authRes = await fetch(`${supabaseUrl}/auth/v1/admin/users`, {
      method: 'POST',
      headers: {
        'apikey': serviceKey,
        'Authorization': `Bearer ${serviceKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        email,
        password: tempPassword,
        email_confirm: true  // skip email confirmation for manually created exec accounts
      })
    });

    const authData = await authRes.json();

    if (!authRes.ok || !authData.id) {
      return new Response(JSON.stringify({ error: authData.message || 'Failed to create auth user.' }), {
        status: 400, headers: { 'Content-Type': 'application/json' }
      });
    }

    const authUserId = authData.id;

    // Step 2 — Insert executive record into executives table
    const execRes = await fetch(`${supabaseUrl}/rest/v1/executives`, {
      method: 'POST',
      headers: {
        'apikey': serviceKey,
        'Authorization': `Bearer ${serviceKey}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation'
      },
      body: JSON.stringify({
        auth_user_id: authUserId,
        university_id: universityId,
        full_name: fullName,
        email,
        role,
        is_active: true
      })
    });

    const execData = await execRes.json();

    if (!execRes.ok) {
      // Rollback: delete the auth user we just created
      await fetch(`${supabaseUrl}/auth/v1/admin/users/${authUserId}`, {
        method: 'DELETE',
        headers: { 'apikey': serviceKey, 'Authorization': `Bearer ${serviceKey}` }
      });
      return new Response(JSON.stringify({ error: 'Failed to create executive record. Auth user rolled back.' }), {
        status: 500, headers: { 'Content-Type': 'application/json' }
      });
    }

    const exec = Array.isArray(execData) ? execData[0] : execData;

    return new Response(JSON.stringify({
      success: true,
      authUserId,
      execId: exec.id,
      email,
      tempPassword  // returned once so the chapter admin can share it — not stored server-side
    }), {
      status: 200,
      headers: { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' }
    });

  } catch (err) {
    return new Response(JSON.stringify({ error: err.message }), {
      status: 500, headers: { 'Content-Type': 'application/json' }
    });
  }
};

export const config = { path: '/netlify/functions/create-executive' };
